import json

with open('/home/user/myproject/chart.html') as f:
    html = f.read()

# Extract the Vega-Lite spec from the HTML
import re
match = re.search(r'var spec = ({.*?});', html, re.DOTALL)
spec = json.loads(match.group(1))

print('=== Mark type ===')
print(spec['mark'])

print('\n=== X encoding ===')
print(spec['encoding']['x'])

print('\n=== Y encoding ===')
print(spec['encoding']['y'])

print('\n=== Color encoding ===')
print(json.dumps(spec['encoding']['color'], indent=2))

print('\n=== Params ===')
print(json.dumps(spec['params'], indent=2))

# Validate acceptance criteria
errors = []

# 1. Mark type must be point or circle
if isinstance(spec['mark'], dict):
    mark_type = spec['mark']['type']
else:
    mark_type = spec['mark']
if mark_type not in ('point', 'circle'):
    errors.append(f'Mark type is {mark_type}, expected point or circle')
else:
    print(f'\n✅ Mark type: {mark_type}')

# 2. X encoding must have sepalLength
if spec['encoding']['x']['field'] != 'sepalLength':
    errors.append(f'X field is {spec[\"encoding\"][\"x\"][\"field\"]}, expected sepalLength')
else:
    print('✅ X field: sepalLength')

# 3. Y encoding must have sepalWidth
if spec['encoding']['y']['field'] != 'sepalWidth':
    errors.append(f'Y field is {spec[\"encoding\"][\"y\"][\"field\"]}, expected sepalWidth')
else:
    print('✅ Y field: sepalWidth')

# 4. Exactly one param with bind.input == select
params = spec['params']
if len(params) != 1:
    errors.append(f'Expected 1 param, found {len(params)}')
else:
    p = params[0]
    if p['bind']['input'] != 'select':
        errors.append(f'bind.input is {p[\"bind\"][\"input\"]}, expected select')
    elif p['bind']['options'] != ['setosa', 'versicolor', 'virginica']:
        errors.append(f'bind.options is {p[\"bind\"][\"options\"]}')
    elif p['bind']['name'] != 'Species: ':
        errors.append(f'bind.name is {repr(p[\"bind\"][\"name\"])}')
    else:
        print('✅ Param: select dropdown with correct options and name')

# 5. Color encoding must be conditional
color = spec['encoding']['color']
if 'condition' not in color:
    errors.append('Color encoding has no condition')
else:
    cond = color['condition']
    if cond.get('field') != 'species' or cond.get('type') != 'nominal':
        errors.append(f'Condition branch does not reference species:N')
    else:
        print('✅ Color condition references species:N')
    if color.get('value') != 'lightgray':
        errors.append(f'Otherwise value is {color.get(\"value\")}, expected lightgray')
    else:
        print('✅ Color otherwise value: lightgray')

if errors:
    print('\n❌ ERRORS:')
    for e in errors:
        print(f'  - {e}')
else:
    print('\n✅ All acceptance criteria met!')
"

